1	import { describe, it, expect, vi, beforeEach } from "vitest";
2	import { screen, fireEvent } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import { VariableRow } from "@/features/assumptions/VariableRow";
5	import { AssumptionProvider, useAssumptions } from "@/features/assumptions/AssumptionContext";
6	import type { Market } from "@/lib/api/types";
7	
8	// ---------------------------------------------------------------------------
9	// Mocks
10	// ---------------------------------------------------------------------------
11	
12	const mockMutate = vi.fn();
13	
14	vi.mock("@/features/session/context", async () => {
15	  const actual = await vi.importActual<typeof import("@/features/session/context")>(
16	    "@/features/session/context",
17	  );
18	  return {
19	    ...actual,
20	    useSession: vi.fn(),
21	  };
22	});
23	
24	vi.mock("@/lib/query/hooks", () => ({
25	  useMarket: vi.fn(),
26	  useProbabilityEdit: vi.fn(),
27	}));
28	
29	import { useSession } from "@/features/session/context";
30	import { useMarket, useProbabilityEdit } from "@/lib/query/hooks";
31	
32	const mockUseSession = vi.mocked(useSession);
33	const mockUseMarket = vi.mocked(useMarket);
34	const mockUseProbabilityEdit = vi.mocked(useProbabilityEdit);
35	
36	// ---------------------------------------------------------------------------
37	// Fixtures
38	// ---------------------------------------------------------------------------
39	
40	const targetMarket: Market = {
41	  id: "mkt-target",
42	  title: "Will it rain tomorrow?",
43	  description: "Rain forecast market",
44	  variableId: "var-target",
45	  status: "active",
46	  outcomes: [
47	    { id: "out-yes", name: "Yes" },
48	    { id: "out-no", name: "No" },
49	  ],
50	  marginals: { "out-yes": 0.65, "out-no": 0.35 },
51	  liquidity: 1000,
52	  volume: 500,
53	  created_at: "2026-01-01T00:00:00Z",
54	  expires_at: "2026-12-31T00:00:00Z",
55	};
56	
57	const otherMarket: Market = {
58	  id: "mkt-other",
59	  title: "Will the sun shine?",
60	  description: "Sun forecast market",
61	  variableId: "mkt-other", // matches id so hasAssumption(m.id) finds the stored assumption
62	  status: "active",
63	  outcomes: [
64	    { id: "out-sun-yes", name: "Sunny" },
65	    { id: "out-sun-no", name: "Cloudy" },
66	  ],
67	  marginals: { "out-sun-yes": 0.7, "out-sun-no": 0.3 },
68	  liquidity: 800,
69	  volume: 300,
70	  created_at: "2026-01-01T00:00:00Z",
71	  expires_at: "2026-12-31T00:00:00Z",
72	};
73	
74	const configuredSession = {
75	  session: { accountId: "acc-123", agentId: "agent-1" },
76	  setAccountId: vi.fn(),
77	  setAgentId: vi.fn(),
78	  isConfigured: true,
79	};
80	
81	const unconfiguredSession = {
82	  session: { accountId: "", agentId: "" },
83	  setAccountId: vi.fn(),
84	  setAgentId: vi.fn(),
85	  isConfigured: false,
86	};
87	
88	function defaultMutationState(overrides: Record<string, unknown> = {}) {
89	  return {
90	    mutate: mockMutate,
91	    mutateAsync: vi.fn(),
92	    reset: vi.fn(),
93	    isPending: false,
94	    isSuccess: false,
95	    isError: false,
96	    isIdle: true,
97	    status: "idle" as const,
98	    data: undefined,
99	    error: null,
100	    variables: undefined,
101	    failureCount: 0,
102	    failureReason: null,
103	    submittedAt: 0,
104	    context: undefined,
105	    ...overrides,
106	  } as unknown as ReturnType<typeof useProbabilityEdit>;
107	}
108	
109	// ---------------------------------------------------------------------------
110	// Helpers
111	// ---------------------------------------------------------------------------
112	
113	/**
114	 * Invisible component that seeds assumptions into context when its
115	 * "seed-assumptions" button is clicked.
116	 */
117	function Seeder({ assumptions }: { assumptions: Array<{ variableId: string; outcomeId: string; label: string }> }) {
118	  const { addAssumption } = useAssumptions();
119	  return (
120	    <button
121	      data-testid="seed-assumptions"
122	      onClick={() => assumptions.forEach((a) => addAssumption(a))}
123	      style={{ display: "none" }}
124	    />
125	  );
126	}
127	
128	/**
129	 * Render VariableRow wrapped in a real AssumptionProvider with optional Seeder.
130	 */
131	function renderVariableRow(
132	  { marketId = otherMarket.id, target = targetMarket, initialAssumptions = [] as Array<{ variableId: string; outcomeId: string; label: string }> } = {},
133	) {
134	  function Wrapper() {
135	    return (
136	      <AssumptionProvider>
137	        <Seeder assumptions={initialAssumptions} />
138	        <VariableRow marketId={marketId} targetMarket={target} />
139	      </AssumptionProvider>
140	    );
141	  }
142	
143	  return renderWithProviders(<Wrapper />);
144	}
145	
146	// ---------------------------------------------------------------------------
147	// Setup
148	// ---------------------------------------------------------------------------
149	
150	beforeEach(() => {
151	  vi.clearAllMocks();
152	  mockUseSession.mockReturnValue(configuredSession);
153	  mockUseProbabilityEdit.mockReturnValue(defaultMutationState());
154	  // Default: useMarket returns the otherMarket
155	  mockUseMarket.mockReturnValue({
156	    data: { market: otherMarket, meta: { requestId: "r1" } },
157	    isLoading: false,
158	    isError: false,
159	    error: null,
160	  } as unknown as ReturnType<typeof useMarket>);
161	});
162	
163	// ---------------------------------------------------------------------------
164	// Tests: Rendering
165	// ---------------------------------------------------------------------------
166	
167	describe("VariableRow", () => {
168	  describe("rendering", () => {
169	    it("returns null when useMarket has no data", () => {
170	      mockUseMarket.mockReturnValue({
171	        data: undefined,
172	        isLoading: true,
173	        isError: false,
174	        error: null,
175	      } as unknown as ReturnType<typeof useMarket>);
176	
177	      renderVariableRow();
178	      // VariableRow returns null — no market title or outcomes rendered
179	      expect(screen.queryByText(/Will the sun shine/)).not.toBeInTheDocument();
180	      expect(screen.queryByText("Assume")).not.toBeInTheDocument();
181	    });
182	
183	    it("renders market title and outcomes with probabilities", () => {
184	      renderVariableRow();
185	
186	      expect(screen.getByText(/Will the sun shine\?/)).toBeInTheDocument();
187	      expect(screen.getByText(/Sunny: 70\.0%/)).toBeInTheDocument();
188	      expect(screen.getByText(/Cloudy: 30\.0%/)).toBeInTheDocument();
189	    });
190	
191	    it("renders '(current)' label for target market", () => {
192	      mockUseMarket.mockReturnValue({
193	        data: { market: targetMarket, meta: { requestId: "r1" } },
194	        isLoading: false,
195	        isError: false,
196	        error: null,
197	      } as unknown as ReturnType<typeof useMarket>);
198	
199	      renderVariableRow({ marketId: targetMarket.id, target: targetMarket });
200	
201	      expect(screen.getByText("(current)")).toBeInTheDocument();
202	    });
203	
204	    it("does not render '(current)' for non-target market", () => {
205	      renderVariableRow();
206	
207	      expect(screen.queryByText("(current)")).not.toBeInTheDocument();
208	    });
209	  });
210	
211	  // ---------------------------------------------------------------------------
212	  // Tests: Assumption toggle
213	  // ---------------------------------------------------------------------------
214	
215	  describe("assumption toggle", () => {
216	    it("renders Assume button for each outcome on non-target market", () => {
217	      renderVariableRow();
218	
219	      const assumeButtons = screen.getAllByText("Assume");
220	      expect(assumeButtons).toHaveLength(2);
221	    });
222	
223	    it("clicking Assume adds assumption and shows badge and button text change", () => {
224	      renderVariableRow();
225	
226	      const assumeButtons = screen.getAllByText("Assume");
227	      fireEvent.click(assumeButtons[0]!);
228	
229	      expect(screen.getByText(/ASSUMED: out-sun-yes/)).toBeInTheDocument();
230	      expect(screen.getByText("✓ Assumed")).toBeInTheDocument();
231	    });
232	
233	    it("clicking assumed button again removes assumption", () => {
234	      renderVariableRow();
235	
236	      // Assume first outcome
237	      const assumeButtons = screen.getAllByText("Assume");
238	      fireEvent.click(assumeButtons[0]!);
239	
240	      // Verify assumed
241	      expect(screen.getByText("✓ Assumed")).toBeInTheDocument();
242	
243	      // Click again to remove
244	      fireEvent.click(screen.getByText("✓ Assumed"));
245	
246	      // Should revert to two "Assume" buttons, no badge
247	      expect(screen.queryByText(/ASSUMED:/)).not.toBeInTheDocument();
248	      expect(screen.getAllByText("Assume")).toHaveLength(2);
249	    });
250	
251	    it("does NOT render Assume button when marketId === targetMarket.id", () => {
252	      mockUseMarket.mockReturnValue({
253	        data: { market: targetMarket, meta: { requestId: "r1" } },
254	        isLoading: false,
255	        isError: false,
256	        error: null,
257	      } as unknown as ReturnType<typeof useMarket>);
258	
259	      renderVariableRow({ marketId: targetMarket.id, target: targetMarket });
260	
261	      expect(screen.queryByText("Assume")).not.toBeInTheDocument();
262	    });
263	  });
264	
265	  // ---------------------------------------------------------------------------
266	  // Tests: Edit flow
