273	          {markets.length} variable{markets.length !== 1 ? "s" : ""}
274	          {conditionalEdges.length > 0 && ` · ${conditionalEdges.length} edge${conditionalEdges.length !== 1 ? "s" : ""}`}
275	          {cliques.length > 0 && ` · ${cliques.length} clique${cliques.length !== 1 ? "s" : ""}`}
276	          {engineStats && ` · JT width ${engineStats.cliques.junction_tree_width}`}
